'use strict';

function renderTable(rows, options) {
  // Calculate column widths
  const columnWidths = [];
  for (let col = 0; col < rows[0].length; col++) {
    let maxWidth = 0;
    for (let row = 0; row < rows.length; row++) {
      maxWidth = Math.max(maxWidth, rows[row][col].length);
    }
    columnWidths[col] = maxWidth;
  }

  // Parse options
  const align = options?.align || new Array(rows[0].length).fill('left');
  const header = options?.header || false;

  // Process rows
  const lines = [];
  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const cells = [];

    for (let col = 0; col < row.length; col++) {
      const cell = row[col];
      const width = columnWidths[col];
      const isLastColumn = col === row.length - 1;

      if (isLastColumn) {
        cells.push(cell);
      } else {
        cells.push(align[col] === 'right' ? cell.padStart(width) : cell.padEnd(width));
      }
    }

    lines.push(cells.join(' '));

    if (header && i === 0) {
      lines.push('-'.repeat(cells.join(' ').length));
    }
  }

  return lines.join('\n');
}

