    const row = rows[i];
    const cells = [];

    for (let col = 0; col < row.length; col++) {
      const cell = row[col];
      const width = columnWidths[col];
      const isLastColumn = col === row.length - 1;

      if (isLastColumn) {
        // Last column: only pad on left for right-align, never on right
        if (align[col] === 'right') {
          cells.push(cell.padStart(width));
        } else {
          cells.push(cell);
        }
      } else {
        // Non-last columns: pad based on alignment
        if (align[col] === 'right') {
          cells.push(cell.padStart(width));
        } else {
          cells.push(cell.padEnd(width));
        }
      }
    }

    lines.push(cells.join(' '));

    // Add header separator after first row if header option is true
    if (header && i === 0) {
      const separatorLength = cells.join(' ').length;
      lines.push('-'.repeat(separatorLength));
    }
  }

  return lines.join('\n');
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = { renderTable, renderTableLegacy };

